// ===============================
// GDocument | Data Provider
// Contract Build
// ===============================

// Función para limpiar textos
function clean(value) {
  if (value === null || value === undefined) return null;

  return String(value).replace(/\r?\n/g, " ").replace(/\s+/g, " ").trim();
}

// Función para obtener campos del serial
function serialField(name) {
  return $json.busqueda?.serial?.[name]?.[0]?.campo ?? null;
}

return {
  json: {
    // ===========================
    // Identificadores
    // ===========================

    id: $json.id,

    radicado: clean($json.radicado),

    // ===========================
    // Cliente
    // ===========================

    empresa: clean($json.busqueda?.cliente),

    ciudad: clean(serialField("Cuidad")),

    sede: clean($json.busqueda?.direccion_de_soporte),

    direccion: clean(
      serialField("Edificio/Dirección") ?? $json.busqueda?.direccion_de_soporte,
    ),

    area: clean(serialField("Ubicación")),

    // ===========================
    // Contacto
    // ===========================

    contacto: clean($json.busqueda?.contacto_cliente),

    telefono: clean($json.busqueda?.celular_del_solicitante),

    // ===========================
    // Equipo
    // ===========================

    marca: clean(serialField("Marca")),

    modelo: clean(serialField("Modelo")),

    serial: clean(serialField("Serial")),

    consumible: clean(serialField("Toner y/o Cintas")),

    // ===========================
    // Ticket
    // ===========================

    tipo_requerimiento: clean($json.busqueda?.tipo_de_requerimiento),

    descripcion: clean($json.busqueda?.descripcion_del_requerimiento),

    tecnico_asignado: clean($json.busqueda?.tecnico_asignado),

    estado: clean($json.busqueda?.estado),

    // ===========================
    // Metadata
    // ===========================

    fecha_extraccion: new Date().toISOString(),

    origen: "GDocument",

    "schema_version": "1.0.0",
  },
};

const crypto = require('crypto');

const ticket = $json;

/*
|--------------------------------------------------------------------------
| Documento semántico
|--------------------------------------------------------------------------
| Este texto será enviado al modelo de embeddings.
| Debe contener únicamente información relevante para comprender
| el contexto técnico del requerimiento.
|--------------------------------------------------------------------------
*/

const documentoSemantico = `
Empresa: ${ticket.empresa ?? ""}

Ciudad: ${ticket.ciudad ?? ""}

Sede: ${ticket.sede ?? ""}

Dirección: ${ticket.direccion ?? ""}

Área: ${ticket.area ?? ""}

Equipo: ${ticket.marca ?? ""} ${ticket.modelo ?? ""}

Serial: ${ticket.serial ?? ""}

Consumible: ${ticket.consumible ?? ""}

Tipo de requerimiento: ${ticket.tipo_requerimiento ?? ""}

Descripción:

${ticket.descripcion ?? ""}
`.trim();



/*
|--------------------------------------------------------------------------
| Contenido para detectar cambios
|--------------------------------------------------------------------------
| Solo incluye campos que modifican el significado del ticket.
| NO incluye estado, técnico, fechas ni información administrativa.
|--------------------------------------------------------------------------
*/

const contenidoHash = [
    ticket.empresa,
    ticket.ciudad,
    ticket.sede,
    ticket.direccion,
    ticket.area,
    ticket.marca,
    ticket.modelo,
    ticket.serial,
    ticket.consumible,
    ticket.tipo_requerimiento,
    ticket.descripcion
]
.filter(Boolean)
.join("|");



/*
|--------------------------------------------------------------------------
| SHA256
|--------------------------------------------------------------------------
*/

const hashDocumento = crypto
    .createHash("sha256")
    .update(contenidoHash)
    .digest("hex");



return {
    json: {
        ...ticket,

        documento_semantico: documentoSemantico,

        hash_documento: hashDocumento
    }
};
